// Transforma filas del Sheet de scraping social a payloads para Supabase.
// Devuelve DOS tipos de items distinguidos por _target:
//   - 'social_competitor' → 1 fila por post del Sheet
//   - 'social_metrics'    → 1 fila por (fecha, plataforma, cuenta) agregando posts del día
//
// Columnas del Sheet (header de la fila 1):
//   RED-SOCIAL | POSTEO | PILAR | POSITIVO | NEGATIVO | NEUTRO | INSIGHT |
//   LIKES | COMENTARIOS | ENGAGEMENT | DATE | TYPE | MARCA | VIEWS |
//   CONTENT_TYPE | SPONSORED | HASHTAGS | FOLLOWERS

const PLATAFORMA_MAP = {
  INSTAGRAM: 'instagram',
  FACEBOOK: 'facebook',
  TIKTOK: 'tiktok',
  YOUTUBE: 'youtube',
  TWITTER: 'twitter',
  LINKEDIN: 'linkedin',
};

const toIsoDate = (v) => {
  if (!v) return null;
  if (v instanceof Date) return v.toISOString().slice(0, 10);
  const s = String(v).trim();
  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  const m = s.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})$/);
  if (m) {
    const [, d, mo, y] = m;
    return `${y}-${mo.padStart(2, '0')}-${d.padStart(2, '0')}`;
  }
  const p = new Date(s);
  return Number.isNaN(p.getTime()) ? null : p.toISOString().slice(0, 10);
};

const toIsoTs = (v) => {
  const d = toIsoDate(v);
  return d ? `${d}T12:00:00Z` : null;
};

const toInt = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(/[^0-9.\-]/g, ''));
  return Number.isFinite(n) ? Math.round(n) : null;
};

const toFloat = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const s = String(v).replace('%', '').replace(',', '.').trim();
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
};

const toBool = (v) => {
  if (typeof v === 'boolean') return v;
  const s = String(v ?? '').trim().toUpperCase();
  return s === 'TRUE' || s === 'SI' || s === 'YES' || s === '1';
};

const slugifyMarca = (v) => String(v ?? '').trim().toLowerCase().replace(/\s+/g, '_');

const hashPostId = (url, fecha, marca) => {
  // Si no hay URL única, derivamos un id desde (fecha+marca+url) para no romper unique.
  const base = `${fecha}|${marca}|${url ?? ''}`;
  let h = 0;
  for (let i = 0; i < base.length; i++) h = ((h << 5) - h + base.charCodeAt(i)) | 0;
  return `auto_${Math.abs(h).toString(36)}`;
};

const posts = [];
const dailyKey = (r) => `${r.fecha_post}|${r.plataforma}|${r.cuenta}`;
const dailyMap = new Map();

for (const item of items) {
  const row = item.json;
  const fecha_post = toIsoTs(row.DATE);
  if (!fecha_post) continue;

  const plataforma = PLATAFORMA_MAP[String(row['RED-SOCIAL'] ?? '').trim().toUpperCase()] ?? 'other';
  const cuenta = slugifyMarca(row.MARCA);
  if (!cuenta) continue;

  const sponsored = toBool(row.SPONSORED);
  const tipo_post = String(row.TYPE ?? '').trim().toUpperCase() || (sponsored ? 'PAUTA' : 'ORGÁNICO');

  const post = {
    fecha_post,
    plataforma,
    cuenta,
    post_id: hashPostId(row.POSTEO, fecha_post.slice(0, 10), cuenta),
    post_url: row.POSTEO ? String(row.POSTEO).trim() : null,
    contenido: row.INSIGHT ? String(row.INSIGHT).trim() : null,
    likes: toInt(row.LIKES),
    comentarios: toInt(row.COMENTARIOS),
    shares: null,
    vistas: toInt(row.VIEWS),
    pilar: row.PILAR ? String(row.PILAR).trim() : null,
    sentiment_positivo: toFloat(row.POSITIVO),
    sentiment_negativo: toFloat(row.NEGATIVO),
    sentiment_neutro: toFloat(row.NEUTRO),
    content_type: row.CONTENT_TYPE ? String(row.CONTENT_TYPE).trim() : null,
    sponsored,
    tipo_post,
    hashtags: row.HASHTAGS ? String(row.HASHTAGS).trim() : null,
    insight: row.INSIGHT ? String(row.INSIGHT).trim() : null,
    source: 'google_sheet',
  };
  posts.push({ json: { _target: 'social_competitor', ...post } });

  // Agregado diario (1 fila por fecha+plataforma+cuenta)
  const fechaDia = fecha_post.slice(0, 10);
  const key = `${fechaDia}|${plataforma}|${cuenta}`;
  const agg = dailyMap.get(key) ?? {
    fecha: fechaDia,
    plataforma,
    cuenta,
    es_competidor: cuenta !== 'dreanargentina',
    seguidores: 0,
    engagement_rate: null,
    posts: 0,
    alcance: null,
    impresiones: null,
    interacciones: 0,
    views: 0,
    posts_organicos: 0,
    posts_pauta: 0,
    sentiment_sum_pos: 0,
    sentiment_sum_neg: 0,
    sentiment_sum_neu: 0,
    sentiment_count: 0,
    source: 'google_sheet',
  };
  agg.posts += 1;
  if (sponsored) agg.posts_pauta += 1; else agg.posts_organicos += 1;
  agg.interacciones += (toInt(row.LIKES) ?? 0) + (toInt(row.COMENTARIOS) ?? 0);
  agg.views += toInt(row.VIEWS) ?? 0;
  agg.seguidores = Math.max(agg.seguidores, toInt(row.FOLLOWERS) ?? 0);
  const sp = toFloat(row.POSITIVO);
  const sn = toFloat(row.NEGATIVO);
  const su = toFloat(row.NEUTRO);
  if (sp !== null && sn !== null && su !== null) {
    agg.sentiment_sum_pos += sp;
    agg.sentiment_sum_neg += sn;
    agg.sentiment_sum_neu += su;
    agg.sentiment_count += 1;
  }
  const eng = toFloat(row.ENGAGEMENT);
  if (eng !== null) {
    agg.engagement_rate = agg.engagement_rate === null ? eng : (agg.engagement_rate + eng) / 2;
  }
  dailyMap.set(key, agg);
}

const dailies = [];
for (const agg of dailyMap.values()) {
  const promedio = (sum) => (agg.sentiment_count > 0 ? sum / agg.sentiment_count : null);
  dailies.push({
    json: {
      _target: 'social_metrics',
      fecha: agg.fecha,
      plataforma: agg.plataforma,
      cuenta: agg.cuenta,
      es_competidor: agg.es_competidor,
      seguidores: agg.seguidores,
      engagement_rate: agg.engagement_rate,
      posts: agg.posts,
      alcance: agg.alcance,
      impresiones: agg.impresiones,
      interacciones: agg.interacciones,
      views: agg.views,
      posts_organicos: agg.posts_organicos,
      posts_pauta: agg.posts_pauta,
      sentiment_promedio_positivo: promedio(agg.sentiment_sum_pos),
      sentiment_promedio_negativo: promedio(agg.sentiment_sum_neg),
      sentiment_promedio_neutro: promedio(agg.sentiment_sum_neu),
      source: agg.source,
    },
  });
}

return [...posts, ...dailies];
